/*========================================================
  CREAR TABLA CAT_ESTADO
========================================================*/
BEGIN
   EXECUTE IMMEDIATE 'DROP TABLE CAT_ESTADO CASCADE CONSTRAINTS';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/

CREATE TABLE CAT_ESTADO (
    UUID_ESTADO VARCHAR2(36)  NOT NULL,
    UUID_PAIS VARCHAR2(36)  default '34a03599-6d56-4c0c-aff0-f887ca20ea93',
    DESCRIPCION VARCHAR2(25) NOT NULL,
    ESTADO NUMBER(2) NOT NULL,
    FECHA_CREACION TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CREADO_POR VARCHAR2(36) NOT NULL,
    FECHA_ACTUALIZACION TIMESTAMP,
    ACTUALIZADO_POR VARCHAR2(36),
    NOTAS VARCHAR2(100),

    CONSTRAINT PK_CAT_ESTADO PRIMARY KEY (UUID_ESTADO),

    CONSTRAINT FK_CAT_ESTADO_PAIS
        FOREIGN KEY (UUID_PAIS)
        REFERENCES CAT_PAIS(UUID_PAIS),

    CONSTRAINT CK_CAT_ESTADO_EESTADO
        CHECK (ESTADO IN (0, 99))
);

COMMENT ON TABLE CAT_ESTADO IS 'Catálogo de estados';
COMMENT ON COLUMN CAT_ESTADO.UUID_ESTADO IS 'UUID del estado';
COMMENT ON COLUMN CAT_ESTADO.UUID_PAIS IS 'Referencia al país';
COMMENT ON COLUMN CAT_ESTADO.DESCRIPCION IS 'Nombre del estado';
COMMENT ON COLUMN CAT_ESTADO.ESTADO IS '0 = Inactivo, 99 = Activo';
COMMENT ON COLUMN CAT_ESTADO.FECHA_CREACION IS 'Fecha de creación';
COMMENT ON COLUMN CAT_ESTADO.CREADO_POR IS 'Usuario creador';
COMMENT ON COLUMN CAT_ESTADO.FECHA_ACTUALIZACION IS 'Fecha de actualización';
COMMENT ON COLUMN CAT_ESTADO.ACTUALIZADO_POR IS 'Usuario actualizador';
COMMENT ON COLUMN CAT_ESTADO.NOTAS IS 'Observaciones';

COMMIT;
